// Rotation des 5 types de hooks selon le jour de la semaine
const day = new Date().getDay(); // 0=dim, 1=lun, 2=mar, 3=mer, 4=jeu, 5=ven, 6=sam

const hooks = {
  0: { type: 'IDENTIFICATION', label: 'Identification Directe', instruction: "Commence par cibler directement la situation du spectateur. Ex: 'T as une idée de marque dans la tête depuis des mois et t as encore rien fait ?' ou 'T es du genre à vouloir lancer ta marque mais tu sais pas par ou commencer ?'. Le spectateur doit se dire : il parle de moi." },
  1: { type: 'BOUCLE_OUVERTE', label: 'Boucle Ouverte', instruction: "Ouvre une boucle que le cerveau DOIT fermer. Ex: 'Y a une erreur que font 90% des gens qui lancent leur marque et qui leur coute 6 mois de retard.' Le spectateur doit AVOIR BESOIN de rester jusqu a la fin pour connaitre la reponse." },
  2: { type: 'CHIFFRE_CHOC', label: 'Chiffre Choc', instruction: "Commence par un chiffre concret et surprenant. Ex: 'J ai lance ma premiere marque avec 300 euros. Voila exactement comment.' ou '73% des marques de fringues closure avant 1 an. Voila pourquoi et comment eviter ca.'. Le chiffre doit etre credible et frapper." },
  3: { type: 'PROMESSE_RAPIDE', label: 'Promesse Rapide', instruction: "Fais une promesse de valeur immediate. Ex: 'En 45 secondes je vais te dire comment trouver ton fabricant sans intermediaire.' ou 'Je vais t expliquer en 3 etapes comment lancer ta marque sans 5000 euros.'. Le spectateur reste pour recevoir ce qui lui a ete promis." },
  4: { type: 'CONTRE_INTUITIF', label: 'Contre-Intuitif', instruction: "Commence par quelque chose d inattendu, mais sans provoquer. Ex: 'Ton logo et tes couleurs, tout le monde s en fout quand tu debutes. Voila ce qui compte vraiment.' ou 'Poster tous les jours sur Instagram est peut etre ta pire erreur.'. Surprend sans agresser." },
  5: { type: 'BOUCLE_OUVERTE', label: 'Boucle Ouverte', instruction: "Ouvre une boucle que le cerveau DOIT fermer. Ex: 'Y a une chose que j aurais voulu savoir avant de lancer ma premiere marque.' Le spectateur doit AVOIR BESOIN de rester jusqu a la fin pour connaitre la reponse." },
  6: { type: 'IDENTIFICATION', label: 'Identification Directe', instruction: "Commence par cibler directement la situation du spectateur. La personne doit se reconnaitre immediatement dans ta description de situation." }
};

const hook = hooks[day];
return [{ json: { hookType: hook.type, hookLabel: hook.label, hookInstruction: hook.instruction, dayIndex: day } }];

